// Existing URLs + titles already in Airtable (Search Existing Signals pull).
const existingRows = $('Search Existing Signals').all();
const norm = (s) => String(s || '').toLowerCase().replace(/[^a-z0-9]+/g, ' ').trim();
const existingUrls = new Set();
const existingTitles = new Set();
for (const item of existingRows) {
  const f = item.json?.fields || item.json || {};
  const u = f['Source URL']; if (u) existingUrls.add(u);
  const t = f['Company'] ? null : null; // (Company is not the title; title-dedup uses Signal Detail/title if present)
  const title = f['title'] || f['Title'] || f['Signal Detail'];
  if (title) existingTitles.add(norm(title));
}

const allRssItems = $input.all();
// Pre-filter: keywords that suggest data-center/power relevance.
const keywords = /\b(data center|datacenter|hyperscale|colo|colocation|interconnection|MW\b|gigawatt|GW\b|PPA|campus|groundbreaking|permit|FERC|VP\b|director|head of|senior director|origination|substation|transmission)\b/i;
const cutoff = Date.now() - 48 * 60 * 60 * 1000;

const newItems = allRssItems
  .filter((item) => {
    const link = item.json.link;
    const title = item.json.title || '';
    const pubDate = new Date(item.json.pub_date).getTime();
    const text = title + ' ' + (item.json.description || '');
    // Dedup on URL OR normalized title (GUIDs/URLs drift across feeds).
    const dupe = (link && existingUrls.has(link)) || (title && existingTitles.has(norm(title)));
    return (
      link &&
      !dupe &&
      (isNaN(pubDate) || pubDate >= cutoff) &&
      keywords.test(text)
    );
  })
  .slice(0, 30); // hard cap to avoid timeout

console.log(`Filtered ${allRssItems.length} RSS items \u2192 ${newItems.length} new (` + existingUrls.size + ` URLs, ` + existingTitles.size + ` titles in Airtable)`);
return newItems;

// After Merge by position, $json has both original RSS fields AND Claude's response.
// Robust JSON parse (fence/prose tolerant) so valid classifications aren't silently
// dropped, and GUARANTEE every created signal gets a valid 1-5 Actionability.
function robustJSON(raw) {
  let t = raw || '';
  const m = t.match(/```(?:json)?\s*([\s\S]*?)```/i); if (m) t = m[1];
  t = t.trim(); const s = t.search(/[\{\[]/); if (s > 0) t = t.slice(s);
  try { return JSON.parse(t); } catch (e) {}
  const last = Math.max(t.lastIndexOf('}'), t.lastIndexOf(']'));
  if (last >= 0) { try { return JSON.parse(t.slice(0, last + 1)); } catch (e) {} }
  return null;
}
const items = [];
for (const item of $input.all()) {
  const { link, content } = item.json;
  const raw = content?.[0]?.text || '';
  const parsed = robustJSON(raw);
  if (!parsed) continue;
  if (!parsed.relevance) continue;
  const score = parsed.signal_score;
  if (score !== 'High' && score !== 'Medium') continue;
  const validTypes = ['FERC Filing', 'News', 'Permit', 'LinkedIn Surge', 'EIA Generation Spike'];
  const signalType = validTypes.includes(parsed.signal_type) ? parsed.signal_type : 'News';
  // Guarantee Actionability: Claude's value if a valid 1-5 integer, else derive from
  // the categorical Signal Score (High->4, Medium->2). No scored signal ships unscored.
  let act = parseInt(parsed.actionability, 10);
  if (!(act >= 1 && act <= 5)) act = (score === 'High' ? 4 : 2);
  items.push({
    json: {
      Company: parsed.company || '',
      'Signal Type': signalType,
      'Signal Detail': parsed.summary || '',
      Location: parsed.state || '',
      'Source URL': link,
      'Signal Score': score,
      'MW Size': (parsed.mw_size != null && Number.isFinite(Number(parsed.mw_size)) ? Number(parsed.mw_size) : null),
      'Outreach Angle': parsed.outreach_angle || '',
      Actionability: act,
      'Actionability Rationale': parsed.actionability_rationale || '',
      'Date Detected': new Date().toLocaleDateString('en-CA', { timeZone: 'America/New_York' }),
      Status: 'Scored'
    }
  });
}
return items;

// Fetch & Flatten Feeds — replaces the 5 RSS Read + Merge + Normalize nodes.
// Loop-fetches each feed, parses RSS 2.0 + Atom (dependency-free), flattens to one
// stream with `category` + `sourceName` on every item. Category flows to Classify so
// DATACENTER vs ENERGY signals are weighted differently. Emits the same field names
// the rest of the workflow already reads (link, pub_date, title, description, source).
const FEEDS = [
  { name: 'DCD', url: 'https://www.datacenterdynamics.com/rss/', category: 'datacenter' },
  { name: 'DCK', url: 'https://www.datacenterknowledge.com/rss.xml', category: 'datacenter' },
  { name: 'Google News', url: 'https://news.google.com/rss/search?q=%22data+center%22+(MW+OR+hyperscale+OR+PPA+OR+groundbreaking+OR+campus+OR+%22interconnection%22)&hl=en-US&gl=US&ceid=US:en', category: 'datacenter' },
  { name: 'Jobs', url: 'https://news.google.com/rss/search?q=(%22data+center%22+OR+hyperscale+OR+colocation)+(%22director+of%22+OR+%22VP+of%22+OR+%22head+of%22+OR+%22senior+director%22)+(development+OR+origination+OR+energy+OR+power)&hl=en-US&gl=US&ceid=US:en', category: 'datacenter' },
  { name: 'Utility Dive', url: 'https://www.utilitydive.com/feeds/news/', category: 'energy' },
  { name: 'POWER Magazine', url: 'https://www.powermag.com/feed/', category: 'energy' },
  { name: 'RTO Insider', url: 'https://www.rtoinsider.com/feed/', category: 'energy' },
  { name: 'Canary Media', url: 'https://www.canarymedia.com/rss.rss', category: 'energy' },
];
const PER_FEED_CAP = 25;
const stripCdata = (s) => String(s == null ? '' : s).replace(/<!\[CDATA\[([\s\S]*?)\]\]>/g, '$1').trim();
const decode = (s) => String(s || '').replace(/&lt;/g,'<').replace(/&gt;/g,'>').replace(/&quot;/g,'"').replace(/&#0?39;|&apos;/g,"'").replace(/&amp;/g,'&');
function tag(b, n) { const m = b.match(new RegExp('<' + n + '(?:\\s[^>]*)?>([\\s\\S]*?)<\\/' + n + '>', 'i')); return m ? decode(stripCdata(m[1])) : ''; }
function link(b) { const r = b.match(/<link(?:\s[^>]*)?>([\s\S]*?)<\/link>/i); if (r && stripCdata(r[1])) return decode(stripCdata(r[1])); const a = b.match(/<link\b[^>]*rel=["']alternate["'][^>]*href=["']([^"']+)["']/i); if (a) return decode(a[1]); const any = b.match(/<link\b[^>]*href=["']([^"']+)["']/i); return any ? decode(any[1]) : ''; }
function looksLikeFeed(b) { return /^\s*(?:<\?xml|<rss[\s>]|<feed[\s>])/i.test(String(b || '').slice(0, 400)); }
function parseFeed(xml) { const blocks = []; const re = /<(item|entry)(?:\s[^>]*)?>([\s\S]*?)<\/\1>/gi; let m; while ((m = re.exec(xml)) !== null) blocks.push(m[2]); return blocks.map((b) => ({ title: tag(b,'title'), link: link(b), description: (tag(b,'description')||tag(b,'summary')||tag(b,'content')).toString().substring(0,1500), pub_date: tag(b,'pubDate')||tag(b,'published')||tag(b,'updated')||tag(b,'dc:date') })); }
const out = [];
const diag = [];
for (const feed of FEEDS) {
  let body = '', status = 0;
  try {
    const res = await this.helpers.httpRequest({ method: 'GET', url: feed.url, timeout: 25000, returnFullResponse: true, headers: { 'User-Agent': 'Mozilla/5.0 (n8n feed-ingest)', Accept: 'application/rss+xml,application/atom+xml,application/xml,text/xml,*/*' } });
    status = res.statusCode; body = typeof res.body === 'string' ? res.body : String(res.body || '');
  } catch (e) { diag.push({ feed: feed.name, error: (e && e.message ? e.message : String(e)).slice(0,120) }); continue; }
  if (!looksLikeFeed(body)) { diag.push({ feed: feed.name, status, bytes: body.length, note: 'not a feed (HTML/soft-404)' }); continue; }
  const items = parseFeed(body);
  let kept = 0;
  for (const it of items.slice(0, PER_FEED_CAP)) {
    if (!it.title || !it.link) continue;
    out.push({ json: { title: it.title, description: it.description, link: it.link, pub_date: it.pub_date, source: feed.name, sourceName: feed.name, category: feed.category } });
    kept += 1;
  }
  diag.push({ feed: feed.name, status, parsed: items.length, kept });
}
console.log('Fetch & Flatten:', JSON.stringify(diag));
return out;

